{"content":"584: void UpstreamRequest::onPoolReady(std::unique_ptr<GenericUpstream>&& upstream,
585:                                   Upstream::HostDescriptionConstSharedPtr host,
586:                                   const Network::ConnectionInfoProvider& address_provider,
587:                                   StreamInfo::StreamInfo& info,
588:                                   absl::optional<Http::Protocol> protocol) {
589:   // This may be called under an existing ScopeTrackerScopeState but it will unwind correctly.
590:   ScopeTrackerScopeState scope(&parent_.callbacks()->scope(), parent_.callbacks()->dispatcher());
591:   ENVOY_STREAM_LOG(debug, "pool ready", *parent_.callbacks());
592:   recordConnectionPoolCallbackLatency();
593:   upstream_ = std::move(upstream);
594:   had_upstream_ = true;
595:   // Have the upstream use the account of the downstream.
596:   upstream_->setAccount(parent_.callbacks()->account());
597: 
598:   host->outlierDetector().putResult(Upstream::Outlier::Result::LocalOriginConnectSuccess);
599: 
600:   if (protocol) {
601:     stream_info_.protocol(protocol.value());
602:   } else {
603:     // We only pause for CONNECT and WebSocket for HTTP upstreams. If this is a TCP upstream,
604:     // unpause.
605:     paused_for_connect_ = false;
606:     paused_for_websocket_ = false;
607:   }
608: 
609:   StreamInfo::UpstreamInfo& upstream_info = *stream_info_.upstreamInfo();
610:   if (info.upstreamInfo()) {
611:     auto& upstream_timing = info.upstreamInfo()->upstreamTiming();
612:     upstreamTiming().upstream_connect_start_ = upstream_timing.upstream_connect_start_;
613:     upstreamTiming().upstream_connect_complete_ = upstream_timing.upstream_connect_complete_;
614:     upstreamTiming().upstream_handshake_complete_ = upstream_timing.upstream_handshake_complete_;
615:     upstream_info.setUpstreamNumStreams(info.upstreamInfo()->upstreamNumStreams());
616:   }
617: 
618:   // Upstream HTTP filters might have already created/set a filter state.
619:   const StreamInfo::FilterStateSharedPtr& filter_state = info.filterState();
620:   if (!filter_state) {
621:     upstream_info.setUpstreamFilterState(
622:         std::make_shared<StreamInfo::FilterStateImpl>(StreamInfo::FilterState::LifeSpan::Request));
623:   } else {
624:     upstream_info.setUpstreamFilterState(filter_state);
625:   }
626:   upstream_info.setUpstreamLocalAddress(address_provider.localAddress());
627:   upstream_info.setUpstreamRemoteAddress(address_provider.remoteAddress());
628:   upstream_info.setUpstreamSslConnection(info.downstreamAddressProvider().sslConnection());
629: 
630:   // Invoke the onUpstreamHostSelected after setting ssl_connection_info_ in upstream_info.
631:   // This is because the onUpstreamHostSelected callback may need to access the ssl_connection_info
632:   // to determine the scheme of the upstream connection.
633:   onUpstreamHostSelected(host, true);
634: 
635:   if (info.downstreamAddressProvider().connectionID().has_value()) {
636:     upstream_info.setUpstreamConnectionId(info.downstreamAddressProvider().connectionID().value());
637:   }
638: 
639:   if (info.downstreamAddressProvider().interfaceName().has_value()) {
640:     upstream_info.setUpstreamInterfaceName(
641:         info.downstreamAddressProvider().interfaceName().value());
642:   }
643: 
644:   stream_info_.setUpstreamBytesMeter(upstream_->bytesMeter());
